// ─── HELPERS ─────────────────────────────────────────────────────────────────
const categoryMap = new Map(categories.map(c => [c.id, c]));

export function getCategoryById(id: string): Category | undefined {
  return categoryMap.get(id);
}

export function getCategoriesForPack(pack: Pack): Category[] {
  return pack.categoryIds
    .map(id => categoryMap.get(id))
    .filter((c): c is Category => c !== undefined);
}

export function mergeCategories(cats: Category[]): { words: string[]; hints: Record<string, string>; name: string } {
  const words: string[] = [];
  const hints: Record<string, string> = {};
  const names: string[] = [];
  for (const cat of cats) {
    words.push(...cat.words);
    Object.assign(hints, cat.hints);
    names.push(cat.name);
  }
  // Shuffle
  for (let i = words.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [words[i], words[j]] = [words[j], words[i]];
  }
  return { words, hints, name: names.join(' + ') };
}
